class Solution:
    def maxProfit(self, prices: list[int]) -> int:
        lo, best = float("inf"), 0     # lo:目前见过的最低买入价;best:最大利润
        for p in prices:
            lo = min(lo, p)            # 更新最低买入价
            best = max(best, p - lo)   # 今天卖出能赚 = 当前价 - 历史最低价
        return best
